import java.util.Scanner;

public class SafeBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Assuming the input buffer can only hold 10 characters
        char[] buffer = new char[10];

        int copyLength = Math.min(input.length(), buffer.length); // Limiting the number of characters to copy

        for (int i = 0; i < copyLength; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

